import React, { useState } from "react";

function RoomFormTable() {
  const [form, setForm] = useState({
    PhongSo: "",
    LoaiPhong: "",
    GiaPhong: "",
    TinhTrang: "trong",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  return (
    <div className="p-6 max-w-lg mx-auto">
      <h1 className="text-2xl font-bold mb-4 text-blue-600">Quản lý phòng</h1>

      {/* Form nhập phòng */}
      <div className="mb-6 p-4 border rounded-2xl shadow bg-white">
        <div className="grid grid-cols-2 gap-4">
          <input
            type="text"
            name="PhongSo"
            placeholder="Số Phòng"
            value={form.PhongSo}
            onChange={handleChange}
            className="border p-2 rounded focus:ring-2 focus:ring-blue-400"
          />
          <select
            name="LoaiPhong"
            value={form.LoaiPhong}
            onChange={handleChange}
            className="border p-2 rounded focus:ring-2 focus:ring-blue-400"
          >
            <option value="">Loại Phòng</option>
            <option value="Bình thường (nhỏ)">Bình thường (nhỏ)</option>
            <option value="Bình thường (to)">Bình thường (to)</option>
            <option value="Cao cấp (nhỏ)">Cao cấp (nhỏ)</option>
            <option value="Cao cấp (to)">Cao cấp (to)</option>
            <option value="Sang trọng">Sang trọng</option>
          </select>
          <input
            type="number"
            name="GiaPhong"
            placeholder="Giá Phòng"
            value={form.GiaPhong}
            onChange={handleChange}
            className="border p-2 rounded focus:ring-2 focus:ring-blue-400"
          />
          <select
            name="TinhTrang"
            value={form.TinhTrang}
            onChange={handleChange}
            className="border p-2 rounded focus:ring-2 focus:ring-blue-400"
          >
            <option value="trong">Trống</option>
            <option value="dadat">Đã đặt</option>
          </select>
        </div>
      </div>

      {/* Bảng 2x4 hiển thị giá trị form */}
      <div className="overflow-x-auto shadow rounded-2xl">
        <table className="w-full border-collapse text-center">
          <thead>
            <tr className="bg-blue-100 text-blue-800">
              <th className="border p-3">Số Phòng</th>
              <th className="border p-3">Loại Phòng</th>
              <th className="border p-3">Giá Phòng</th>
              <th className="border p-3">Tình Trạng</th>
            </tr>
          </thead>
          <tbody>
            <tr className="bg-white">
              <td className="border p-3">{form.PhongSo}</td>
              <td className="border p-3">{form.LoaiPhong}</td>
              <td className="border p-3">{form.GiaPhong}</td>
              <td
                className={`border p-3 font-semibold ${
                  form.TinhTrang === "trong" ? "text-green-600" : "text-red-500"
                }`}
              >
                {form.TinhTrang === "trong" ? "Trống" : "Đã đặt"}
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default RoomFormTable;
